section.programlisting:
route {
    if (is_method("INVITE") && !has_totag()) {
        credit_check("$fU");
        # Set initial timeout to recheck_interval_secs
        $DLG_timeout = 60;
    }
}
route[on_timeout] {
    credit_recheck("$fU");
    if ($var(credit_max_duration) > 0) {
        # Extend the call
        set_dlg_timeout($var(credit_max_duration));
    }
    # else: credit exhausted, dialog expires naturally
}

section.para:
JSON field name (or dot-separated path) to extract the balance
from the billing API response. Supports nested field access
using dot notation. For example:



	balance matches
	{"balance": 42.5}



	data.account.balance
	matches
	{"data":{"account":{"balance":42.5}}}

example.programlisting:
...
route {
    if (is_method("INVITE") && !has_totag()) {
        if (!credit_check("$fU")) {
            sl_send_reply(402, "Insufficient Credit");
            exit;
        }
        xlog("L_INFO", "$fU: balance=$var(credit_balance) max=$var(credit_max_duration)s\n");
    }
}
...

...
route {
    if (is_method("INVITE") && !has_totag()) {
        if (!credit_check_dest("$fU", "$rU")) {
            sl_send_reply(402, "Insufficient Credit");
            exit;
        }
        xlog("L_INFO", "rate=$var(credit_rate) max=$var(credit_max_duration)s\n");
    }
}
...

...
modparam("rust_credit_check", "cache_warmup_url", "http://billing:8080/all_accounts")

route {
    if (is_method("INVITE") && !has_totag()) {
        # Instant on cache hit (most calls after startup)
        if (!credit_check_async("$fU")) {
            sl_send_reply(402, "Insufficient Credit");
            exit;
        }
    }
}
...

...
modparam("rust_credit_check", "debit_url", "http://billing:8080/debit")
modparam("rust_credit_check", "debit_on_end", 1)

route {
    if (is_method("INVITE") && !has_totag()) {
        credit_check("$fU");  # records call start
    }
    if (is_method("BYE")) {
        credit_end("$fU");    # computes duration, sends debit
    }
}
...

...
modparam("rust_credit_check", "recheck_interval_secs", 60)

route {
    if (is_method("INVITE") && !has_totag()) {
        credit_check("$fU");
        $DLG_timeout = 60;  # re-check every 60 seconds
    }
}
route[on_timeout] {
    credit_recheck("$fU");
    if ($var(credit_max_duration) > 0) {
        set_dlg_timeout($var(credit_max_duration));
    }
}
...

...
route {
    if (is_method("BYE")) {
        # Force balance refresh after call ends
        credit_clear("$fU");
    }
}
...
